mapper.select:
SELECT COUNT(*) as totalOrders, SUM(CASE WHEN status = 4 THEN 1 ELSE 0 END) as completedOrders, SUM(CASE WHEN status = 5 THEN 1 ELSE 0 END) as cancelledOrders, COALESCE(SUM(total_amount), 0) as totalAmount, COALESCE(SUM(pay_amount), 0) as payAmount, COALESCE(SUM(discount_amount), 0) as discountAmount, COALESCE(SUM(CASE WHEN pay_type = 1 THEN pay_amount ELSE 0 END), 0) as balancePayAmount, COALESCE(SUM(CASE WHEN pay_type = 2 THEN pay_amount ELSE 0 END), 0) as alipayAmount, COALESCE(SUM(CASE WHEN pay_type = 3 THEN pay_amount ELSE 0 END), 0) as wechatPayAmount, COALESCE(AVG(pay_amount), 0) as avgOrderAmount FROM `order` WHERE 1=1
AND shop_id = #{shopId}
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}

SELECT COUNT(DISTINCT user_id) as totalCustomers
FROM `order`
WHERE 1=1

    AND shop_id = #{shopId}


    AND DATE(create_time) >= #{startDate}


    AND DATE(create_time) <= #{endDate}

SELECT id, shop_id as shopId, shop_name as shopName, report_date as reportDate, report_type as reportType, total_orders as totalOrders, completed_orders as completedOrders, cancelled_orders as cancelledOrders, total_amount as totalAmount, pay_amount as payAmount, discount_amount as discountAmount, wechat_pay_amount as wechatPayAmount, alipay_amount as alipayAmount, balance_pay_amount as balancePayAmount, avg_order_amount as avgOrderAmount, total_customers as totalCustomers, new_customers as newCustomers, create_time as createTime, update_time as updateTime FROM financial_report WHERE 1=1
AND shop_id = #{shopId}
AND report_type = #{reportType}
AND report_date >= #{startDate}
AND report_date <= #{endDate}
ORDER BY report_date DESC
